import{_ as e,o as b,c as t,j as r,a,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"程式升华钥","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/1.生理类/假面骑士01/程式升华钥.md","filePath":"4.资源分区/2.改造与功法/改造/1.生理类/假面骑士01/程式升华钥.md"}'),n={name:"4.资源分区/2.改造与功法/改造/1.生理类/假面骑士01/程式升华钥.md"};function i(s,p,h,l,c,d){return b(),t("div",null,[...p[0]||(p[0]=[r("h1",{id:"程式升华钥",tabindex:"-1"},[a("程式升华钥 "),r("a",{class:"header-anchor",href:"#程式升华钥","aria-label":'Permalink to "程式升华钥"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调014")])])],-1),o('<h1 id="程式升华钥-1" tabindex="-1">程式升华钥 <a class="header-anchor" href="#程式升华钥-1" aria-label="Permalink to &quot;程式升华钥&quot;">​</a></h1><p>【密钥】类资源：<br> 科技本质奇物，变身时使用的电子钥匙卡型道具。保管了各类生物的数据，加载入零一系统后可提升使用者的不同能力。<br> 所有密钥必须在完成变身后才能使用，各密钥的标准使用方法为：以一个移动动作，你将密钥激活并插入【飞电零一驱动器】，信号发送给卫星泽亚后，装甲数据会被传送至你的身上完成各形态的着装<br> 密钥同时只能生效一个，已在密钥着装状态下使用另一个密钥，将会失去前一个密钥的效果。</p><p>在重复制作同等级的密钥过程中，卫星泽亚会学习经验以提高效率，在你已购买至少一个某等级密钥后，你的下一次购买同等级密钥时会额外解锁【已购买密钥次数-1】个同级别密钥。</p><p>C级密钥：价格C+1000<br> 【高跃蝗虫】程式升华钥<br> A jump to the sky turns to a riderkick</p><p>“通过足部强化装置爆发性地提升脚力从而获得能够越过20层建筑级别的卓越跳跃力及超绝的踢力”<br> 该形态下，你可以以跳跃检定代替移动，跳跃视作已完成助跑。<br> 当你在移动过程中进行了一次成功的跳跃时，你的本次移动速度提升30米<br> 你的腿部天生武器伤害提升6L，并获得【贯穿】特性，在使用腿部天生武器进行冲锋攻击时基础防御不承受减值</p><p>【射击野狼】程式升华钥<br> The elevation increases as the bullet is fired</p><p>“动态视力为人类的8倍，同时配备了专为超精密射击设计的射击统制系统，针对攻击范围的目标可以进行误差0.05mm内的超精密射击”<br> 购买时，绑定一项你已有的，尚未接受改造的科技本质步枪/狙击枪，卫星泽亚会对该武器进行改造，使其适配该形态，你可以在回归主神空间后替换绑定的枪械，解除绑定后原武器恢复原样<br> 该武器伤害提升提升6L，子弹附加束缚效果，命中时造成2点不可豁免的纠缠点数<br> 射击辅助程序使你在使用绑定的枪械射击时，视作已经瞄准了2轮<br> 深度学习AI将会总结每一次战斗的经验，每场影片过后，该形态能使你的瞄准加值和瞄准加值上限提升1</p><p>【冲刺猎豹】程式升华钥<br> Try to outrun this demon to get left in the dust</p><p>“强化装甲飞跃提升装着者的脚力，能针对各种路面情况进行奔驰。不容追随的加速与爆发力能同时对应复数敌人，蕴含着极高的潜力”<br> 购买该资源时，选择一种你已有的攻击检定方式，选定后不可更改<br> 获得等同于基础移动速度的水面速度<br> 该形态下，在战斗中每持续移动一轮，你获得一层【加速】，每层【加速】会为你带来1点闪避防御、2点反射豁免加值和已选攻击检定方式的1点【高速】。加速层数的上限为你的敏捷值，战斗结束后加速层数清空<br> 在你的回合外，针对你能认知到一次攻击，可以反射动作透支下个回合的标准动作打断性的进行一次距离不大于移动速度的移动，这会正常消耗你的标准动作</p><p>【撕咬鲨鱼】程式升华钥<br> Fangs that can chomp through concrete</p><p>&quot;能够借助胸部的呼吸装置和腿部的推进器在水中自由潜航并高速游泳。两腕的锋利臂刃能够进行切断&quot;<br> 该形态下，你获得等同于基础移动速度的游泳速度和固体物质穿行速度，自带水下自由呼吸能力<br> 双臂和腿部装甲装有突出外侧的一体型臂刃，仿造鲨鱼齿的形状，可弹射飞出，在一定距离内遥控进行切割<br> 你的天生武器提升2L，获得【破甲3】，可以造成切割伤害<br> 你以天生武器进行近战肉搏检定时，可以同时对触及范围内的所有敌方单位造成伤害，反射减免</p><p>【飞翔猎隼】程式升华钥<br> Spread your wings and prepare for a force</p><p>&quot;借助背部和腿部装甲内置的安定翼能进行高速飞行&quot;<br> 该形态下，你获得等同于你的移动速度的完美飞行能力<br> 为了适应飞行状态下的机动侦查，该形态能够将来自卫星泽亚的超高度观测情报投影到自身的视界。这视作一种基于视觉的C级科技本质侦测等级<br> 同时，该形态配置的钢铁羽翼可以射出进行攻击，具有基础伤害4L，视作飞刀并使用相关技能/专业进行检定，具有【回力】特性</p><p>【燃焰老虎】/【冰冻极熊】/【闪电黄蜂】程式升华钥<br> Explosive power of one hundred bombs<br> Fierce breath as cold as arctic winds<br> Piercing needle with incredible force</p><p>能量外放型的三种密钥，因为主要能力在于施加不同性质的能量伤害，效果相似，放在一同给出<br> 该形态下，你天生武器进行近战肉搏检定时获得等同于你决心附加成功数目的【火焰】/【寒冷】/【雷电】能量加值，并拥有【威猛5】/【破甲5】/【高速5】<br> 命中时，附加不可豁免的【2点燃烧】/【2点冻结+1点疲乏】/【2点麻痹+1点目眩】异常点数（创伤来源）<br> 若你有【火焰】/【寒冷】/【雷电】相关的能量，则你可以将周围的对应种类能量化为己用，一次性的获得等同于你决心附加成功数目的能量，可以超出能量池上限，战斗结束后不保留。</p><p>【拳击金刚】程式升华钥<br> Enough power to annihilate a mountain</p><p>“身上的重甲在可以承受战车炮直击的同时大幅度提升腕力。手腕的打击武器不仅能够利用进行物理破坏，也能在充能后进行喷射弹出”<br> 该形态下，你的格挡防御提升5点<br> 你的手臂天生武器伤害提升6L，具有【回力】、【毁灭】特性，可当作投掷武器进行攻击检定<br> 深度学习AI将会总结每一次战斗的经验，每场影片过后，该形态能为你的力量属性额外提供1点器械加值</p><p>【针刺毒蝎】程式升华钥<br> Stung with fear by the power claws</p><p>“装备的伸缩突刺单元能够精制高浓度的生物毒素或电子病毒，在穿刺敌人的同时强力注入，装着者自身的攻击能力被极限引发”<br> 该形态下，你的天生武器伤害提高3L，使用天生武器进行近战肉搏检定命中时，对目标造成不可豁免的1点毒素点数<br> 之后，目标每有3点不良状态，则额外受到1点毒素点数，强韧豁免</p><p>【惊异长戟大兜虫】程式升华钥<br> With mighty horn like pincers that flip the opponent helpless</p><p>”胸肌、腕部和腿部的强化装甲将筋力最大限度强化，头部的角可以根据装着者的意思长大化，蕴藏着一挥就能将巨大的对象猛甩出去的力量“<br> 你的力量检定获得等同于你决心附加成功数的器械加值<br> 头部巨角作为天生武器时，提升武器伤害6L，可以自由伸长至多6m，命中可以选择令目标被击飞一轮，这是B级击飞效果</p><p>【闪光长颈鹿】程式升华钥<br> Bursting sparks fly at full force</p><p>”胸部装甲内置的大容量电池直连身体各处装甲，能够进行强力的电击攻击。同时，头部的鹿角作为电极，能以放出电光的头槌击倒敌人“<br> 该形态下，你使用天生武器进行的近战肉搏伤害可以造成闪电伤害，命中时附加2点不可豁免的【麻痹】点数<br> 当你进行一次近战攻击后，闪电可以在目标身上连锁并弹射，随机命中目标10m范围内的另一个未受到此攻击影响的目标，你每次攻击最多弹射等同于你的决心附加成功数。对于范围伤害类技能，一个单位也只会受到一次影响。<br> 装甲内置的电池可用于对其他耗电物品进行充能，你可以迅捷动作向耗电物品充电或是向拥有电能相关能量池的友方补充6点能量（若是电力则是等同6点能量的电力。），这一用法一次变身只能使用一次。一日内你至多以此方式补充你决心属性点能量。</p><p>【破坏猛犸】程式升华钥<br> Larger than life to crush like a machine</p><p>“能以强大的力量和质量将敌人压溃，也可以用能够卸下的胸牙扫荡所有事物。以从大规模灾害中保护人们为目的而开发，因此作为大型救助系统的机能也有多数搭载”<br> 你与卫星泽亚投下的大型救灾机械合体，成为巨型机器人，体积增加25，这部分体积不会带来额外生命上限。并忽视因体积增加而受到的5点高速<br> 你使用天生武器的近战肉搏攻击附带【碾压】特性</p><p>【机枪刺猬】程式升华钥<br> Infinite spines shoot towards the enemy</p><p>“装甲各部锋利的刺仅仅触碰也能给予伤害，战斗时身体可以变化为球形高速回旋的同时向敌人突击、将全身的刺向全方位扫射”<br> 该形态下，每当接触范围内的敌人对你攻击，就向对方造成等同于你改造等级的穿刺严重伤害<br> 这来源于假面骑士零一改造变身时的盔甲防御，当你失去这一防御时你将不再享有该效果的好处<br> 此外，你可以将身上的尖刺发射出去，视作机枪并使用对应技能/专业进行检定，具有武器伤害6L，【连射】、【无限子弹】特性</p><p>【粉碎水牛】程式升华钥<br> This charge attack will send you flying</p><p>“包裹厚重装甲的刚足能产生强大的推进力，利用足尖的蹄放出的踢击一击就足以粉碎敌人。头部超硬度的角在突进时能轻易击碎岩盘”<br> 每轮一次，你以天生武器进行近战肉搏检定时可以附加一次冲撞，并令此次攻击检定获得等同于你力量属性附加值的【威猛】<br> 你每以这种方式击退敌人2米，就使对方失去1点基础防御，上限等同于你的力量属性值<br> 你可以活用水牛的爆发冲刺力，用力量属性代替敏捷来进行反射豁免检定</p><p>【捕获蜘蛛】程式升华钥<br> No one can escape its web</p><p>”搭载了在墙面无声移动等多种奇袭用机能，战斗时能够自在地操纵两腕和两足生成的4根突刺臂攻击敌人。也能从装甲隙间射出电磁拘束网布下陷阱“<br> 你获得额外四只机械臂，每只可以握持一把单手武器<br> 但机械臂本身不会给你带来额外的动作，握持武器的效果也不能共享/同时生效，你每次攻击时需自行选择要使用的武器<br> 随着改造等级的提升，机械臂的AI也将更加灵活，你的器用技能提升等同于你的改造等级。</p><p>无声移动系统可以使你在潜行状态下自由行走不受限制<br> 你能向15m扇形范围内的敌人射出电磁拘束网，以智力+器用：计算机进行检定，对范围内所有敌人造成等同于出目的【麻痹】点数，反射豁免</p><p>【激励锹甲】程式升华钥<br> Razor sharp blades will cross paths</p><p>”在变身者陷入穷地时会启动引发其斗争本能的激励模式，如同愤怒的锹甲般发动猛攻、打开胜利的突破口。擅长夹击敌人的切断技“<br> 该形态下，你免疫【亢奋】点数带来的减值<br> 每轮一次，当你受到伤害时，可以将最多1点严重伤害转化为等量不可豁免的【亢奋】点数，以这种方式获得的亢奋点数在解除变身后仍然存在<br> 当你以天生武器发动近战肉搏攻击时，每有6点【亢奋】点数就获得1点士气加值，上限等同于你的决心属性值</p><p>【喷溅鲸鱼】程式升华钥<br> An aqua current that encompasses everything around it</p><p>”擅长利用装甲内置的放水单元和超音波武器展开攻击，能够将大气中的水分提取形成巨大的鲸鱼尾向敌人对象猛烈劈下，以足以使大地震颤的冲击造成高伤害“<br> 该形态下，你可以提取大气中的水分，再通过防水单元操纵水流来进行攻击，使用智力+器用：计算机+辅助专业：信息学进行检定，具有基础伤害5L，基础射程15m<br> 你也可以选择将水分围绕在身体周围来改变你的外表、体积（变动程度不超过20）、声音、衣物，这视作一个B级、幻象来源的伪装效果<br> 此外，你可以在使用天生武器进行近战肉搏攻击时用超音波武器辅助攻击，这使得你的天生武器伤害类型变为声波，并获得C级传送攻击效果</p><p>【风暴企鹅】程式升华钥<br> The winds are at his command</p><p>”流线型的装甲内置了推进装置，在水中战能进行高速度移动，陆地战则能施展暴风攻击“<br> 该形态下，你获得等同于移动速度的游泳速度，附带水下呼吸能力<br> 在体内的风力引导装置全开的情况下，可以在周围引起暴风施加干扰，以你为中心的触及范围内视作B级环境来源的困难地形<br> 在开启暴风干扰的状态下，强大的风力会使高速运动的物体产生偏移，每轮过后，你可以忽视进攻方的2点【高速】，至多忽略敏捷属性点。<br> 受到攻击时，【忽视高速】超出的部分每有4点就使你获得1点偏斜防御，上限等同于你的敏捷属性值。退出形态后失去该效果。</p><p>【侦查熊猫】程式升华钥<br> There is nothing unknown to his eyes</p><p>”具有专注于侦查的机能，能够收集·分析对象的所有信息辅助战斗。同时，还擅长使用武器，能够立刻学习掌握从敌人处缴获的枪械等武器的使用方法“<br> 该形态的面部侦查单元集成了大量观测仪器，这视作一种基于视觉的B级科技本质侦测等级<br> 当你以这种方式进行侦测时，可以针对范围内一名目标进行额外的解析行为，你选择对方的指定信息类型（攻击、防御、某一豁免、某项免疫等），接着对方额外进行一个伪装检定对抗你的侦查检定，对方失败则获取指定信息，同一目标最多解析5次，这是一种B级信息来源的解析效果<br> 此外，使用该形态的侦查单元也能有效提升瞄准精度，在该状态下你的瞄准上限提升等同于你的改造等级</p><p>【蹦跳袋鼠】程式升华钥<br> It&#39;s pouch contains infinite possibilities</p><p>”装甲配备了能将同伴传送至周围的口袋型特殊次元装置，可以借助不同职业的同伴的特点协助战斗“<br> 该形态下，你将获得一个拥有1000立方米的异次元储物空间，你可以通过你盔甲上的口袋打开它<br> 该空间能够在非战斗状态下储存无助或者自愿状态下的活物，从存储空间内取出物品是一个移动动作，这是一个B级、时空来源的异空间效果</p><p>此外，你可以标记最多3位同伴，受到你标记的同伴的协助效果，对于每位同伴，选取其等级最高的技能，你的这些技能等级提升1级<br> 之后，同伴的技能每有2点附加成功，则你的对应技能等级提升1点，不能超过内在上限<br> 若同伴选取的技能存在重复，则技能等级较低的同伴选取次高的技能进行加成，以此类推。<br> 你无法同时享受三项技能等级的提升，每轮开始时你必须选择其中一个生效，退出形态后失效</p><p>【战斗胡狼】程式升华钥<br> Deciding the fate of a battle like a Valkyrie</p><p>”战斗时除了以手臂的爪进行切裂攻击外，还能将胡狼型的战术支援单位群实体化并狩猎敌人。此外，通过光学操作将自身化为幻影，对视觉机能进行精神骇进等战术也能使用“<br> 你可以在触及范围内召唤胡狼形的战术支援单位，它们接受你的遥控命令，如同你手脚的延伸<br> 胡狼支援单位没有实体，但具有真实的外貌细节，可以在你的触及范围内自由移动、传递信息，这是一个B级幻象效果<br> 当你使用天生武器进行近战肉搏攻击时，可以操纵胡狼幻象来迷惑、限制敌人，使你的这次攻击附加B级措手不及，可以同时攻击2个敌人，并且攻击命中后，可以令目标进行一次反射豁免，Dc为成功数，失败则向任意方向被拖拽失败值米。</p><p>【爆炸狮子】程式升华钥<br> A beautiful explosive force like fireworks</p><p>“使用炸弹和巨爪的复合式武装，身上鬃毛型炸药所释放的爆炸威力十分强悍”<br> 该形态下，你的天生武器伤害提升2L，使用天生武器进行近战肉搏伤害时，可以选择将攻击的结果转化为在目标身上留下一份炸药<br> 炸药会在目标的下一次行动开始时爆炸，爆炸伤害等同于你这次攻击的出目，对命中位置半径15m的圆形范围内所有目标造成伤害（敌我不分），强韧豁免。<br> 你可以自由选择将炸药的爆炸时间延迟，但最多不会超过一个场景/15分钟，超过时间立即引爆，这是一个D级的延迟生效效果<br> 无论如何，你在一个人身上最多留下一份炸药，当你向一个已有炸药的目标施加第二个炸弹时，会立即引爆目标身上的所有炸弹。</p><p>【入侵蝎鲎】程式升华钥<br> Heavily produced battle armor equipped with extra battle specifications</p><p>“受到损伤之际如脱皮一般清除装甲、生成更加强固也更厚的装甲，可喷出青色的特殊液体，附加石化状态“<br> 该形态下，每轮一次，当你受到带有【破甲】特性的攻击时，你将在下一轮额外获得等同于【破甲】数量的盔甲防御，持续一轮，上限等同于你的决心属性值<br> 当你使用天生武器进行近战肉搏检定时，可以附加不可豁免的1点【纠缠】和1点【眩晕】点数，若是使目标同时进入【定身】和【昏迷】状态，则视作使对方进入【石化】状态</p><p>B级：B+2000</p><p>程式升华钥自B级开始，便具有了定向的适配性，通常一个人只能完全发挥出一枚程式升华钥完整效果<br> 当你有复数枚程式升华钥时，你只能选择其中一枚作为适配密钥并获得它的常驻效果，其余密钥的常驻效果不适用<br> 你也可以接受主神空间的改造调整，使你可以同时适配复数个密钥，每个额外的适配密钥花费12xp，可以使用【数据】抵价。</p><p>特别的，你能以对应的C级密钥差价升级为B级密钥<br> 差价升级时，原C级密钥的价格视作你【最后一次购买的C级密钥】的价格，目标B级密钥的价格遵循重复购买的减价规则<br> 差价升级后，你的C级密钥购买数量减一，B级密钥购买数量加一</p><p>【闪耀蝗虫】程式升华钥<br> 差价升级：【高跃蝗虫】程式升华钥<br> When I shine, darkness fades</p><p>&quot;脚部是尤其调整了强力的反作用力的部位，能够在垂直起跳的情况下，到达70米的高度。由此，通过再现蝗虫的机能，着装者的能力得到了扩展。&quot;<br> 变身状态下，你将获得【飞跃移动】和【蝗虫踢击】特性<br> 【飞跃移动】：你可以以跳跃检定代替移动，跳跃视作已完成助跑。当你在移动过程中进行了一次成功的跳跃时，你的本次移动速度提升60米<br> 【蝗虫踢击】：你的腿部天生武器伤害提升9L，并获得【超级贯穿】特性，在使用腿部天生武器进行冲锋攻击时基础防御不承受减值</p><p>此外，你常态获得【神速反应】特性<br> 【神速反应】：你始终视作处于格挡状态</p><p>【突击野狼】程式升华钥<br> 差价升级：【射击野狼】程式升华钥<br> No chance of surviving in this shot</p><p>若你是以【射击野狼】密钥差价提升为此密钥，<br> 则当你处于变身状态下，继承通过【射击野狼】获得的&quot;提升瞄准加值与瞄准上限&quot;的好处<br> 但你不能再通过【射击野狼】密钥获得瞄准加值与瞄准上限的增长。</p><p>&quot;全身重装甲化的同时在各部位搭载了武器库，利用微型导弹和多重锁定激光可施展大火力的强袭作战。同时，虽然通过战斗辅助装置大幅提高战斗力，但去除了安全装置和生命维持装置，极限追求能力而不考虑变身者的负担&quot;<br> 变身状态下，你将获得【突击武器库】特性<br> 【突击武器库】：<br> 你身上搭载着多种射击武器，你可以选择你熟悉的一种进行攻击，使用敏捷+射击：任意专业+辅助专业：弹道学进行攻击检定<br> 具有【无限子弹】特性，武器伤害9L，20m扇形射程，可以同时攻击到射程内的所有敌人。</p><p>若你已有正在使用的枪械，也可以借用武器库中的火力进行掩护<br> 绑定一项你已有的，尚未接受改造的科技本质步枪/狙击枪，你使用它进行射击检定获得【威猛6】、【破甲3】</p><p>无论如何，你无法在同一轮中使用武器库同时进行攻击和掩护，必须选择二者之一的效果使用</p><p>此外，你常态获得【战斗辅助装置】特性<br> 【战斗辅助装置】：<br> 以一个迅捷动作启动，对自己造成等同于自身决心附加成功数的不可豁免的严重伤害（至少1点）<br> 直到本轮结束为止，你以【突击武器库】或绑定的枪械命中目标时，每有10点瞄准加值就附加1点不可豁免的纠缠点数</p><p>【燃烧猎隼】程式升华钥<br> 差价升级：【飞翔猎隼】程式升华钥<br> The strongest wings bearning the fire of hell</p><p>“飞行时利用缠绕着业火的红莲之翼，化为炎之猎隼向敌人突击。 ”<br> 变身状态下，你将获得【燎原火羽】特性<br> 【燎原火羽】：你获得等同于你的移动速度的完美飞行能力。你背后的羽翼视作飞刀，使用相关的技能/专业进行检定<br> 具有基础武器伤害9L，【回力】特性，命中时附加1点不可豁免的燃烧点数。</p><p>此外，你常态获得【浴火重生】特性<br> 【浴火重生】：<br> 当你死亡后，你获得一次B级、信息来源的复活效果，需要三个月的时间复活<br> 在此期间你以数据态存活于电子产品中（视作灵体），除了观察和移动外无法进行更多的动作，具有等同于你的意志力的结构值，被摧毁则复活失败。<br> 你每场影片最多以这种方式复活一次</p><p>【惊异南洋大兜虫】程式升华钥<br> 差价升级：【惊异长戟大兜虫】程式升华钥<br> When the three horns cross, the golden soldier is born</p><p>”蕴藏着惊人怪力的强化装甲表层覆盖着硬化树脂涂层，极大地提升防御力和装甲的华丽度“<br> 变身状态下，你将获得【三角强化】和【惊异巨角】特性 【树脂盔甲】：你使用力量属性的近战肉搏检定获得等同于你决心附加成功数的器械加值，并且再提升等量盔甲防御 【惊异巨角】：头部巨角视作提升9L武器伤害的天生武器，可以自由伸长至多10m，命中可以选择令目标被击飞一轮，这是B级击飞效果</p><p>此外，你常态获得【千兆劫取】特性<br> 【千兆劫取】：选定一项你拥有的【C级程式升华钥】，支付6XP或等量资源，你可以将其中的数据劫取至【惊异南洋大兜虫】密钥中<br> 当你使用【惊异南洋大兜虫】密钥变身时，视作你同时使用【惊异南洋大兜虫】和选定的【C级程式升华钥】变身，并同时享有双方的效果<br> 你可以重复支付6xp或等量资源，将另一种【C级程式升华钥】数据劫取至【惊异南洋大兜虫】密钥中<br> 当你变身时，需要选择启用哪一种【C级程式升华钥】的效果，你也可以以一个移动动作切换正在使用的【C级程式升华钥】效果<br> 无论如何，你最多同时享受【惊异南洋大兜虫】和一种【C级程式升华钥】的增幅效果</p><p>* * *</p><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',69)])])}const m=e(n,[["render",i]]);export{f as __pageData,m as default};
